61: /**
62:  * <p>
63:  *     KafkaBasedLog provides a generic implementation of a shared, compacted log of records stored in Kafka that all
64:  *     clients need to consume and, at times, agree on their offset / that they have read to the end of the log.
65:  * </p>
66:  * <p>
67:  *     This functionality is useful for storing different types of data that all clients may need to agree on --
68:  *     offsets or config for example. This class runs a consumer in a background thread to continuously tail the target
69:  *     topic, accepts write requests which it writes to the topic using an internal producer, and provides some helpful
70:  *     utilities like checking the current log end offset and waiting until the current end of the log is reached.
71:  * </p>
72:  * <p>
73:  *     To support different use cases, this class works with either single- or multi-partition topics.
74:  * </p>
75:  * <p>
76:  *     Since this class is generic, it delegates the details of data storage via a callback that is invoked for each
77:  *     record that is consumed from the topic. The invocation of callbacks is guaranteed to be serialized -- if the
78:  *     calling class keeps track of state based on the log and only writes to it when consume callbacks are invoked
79:  *     and only reads it in {@link #readToEnd(Callback)} callbacks then no additional synchronization will be required.
80:  * </p>
81:  * <p>
82:  *     This is a useful utility that has been used outside of Connect. This isn't in Connect's public API,
83:  *     but we've tried to maintain the method signatures and backward compatibility since early Kafka versions.
84:  * </p>
85:  */
86: public class KafkaBasedLog<K, V> {
87:     private static final Logger log = LoggerFactory.getLogger(KafkaBasedLog.class);
88:     private static final long CREATE_TOPIC_TIMEOUT_NS = TimeUnit.SECONDS.toNanos(30);
89:     private static final long MAX_SLEEP_MS = TimeUnit.SECONDS.toMillis(1);
90:     // 15min of admin retry duration to ensure successful metadata propagation.  10 seconds of backoff
91:     // in between retries
92:     private static final Duration ADMIN_CLIENT_RETRY_DURATION = Duration.ofMinutes(15);
93:     private static final long ADMIN_CLIENT_RETRY_BACKOFF_MS = TimeUnit.SECONDS.toMillis(10);
94: 
95:     private final Time time;
96:     private final String topic;
97:     private int partitionCount;
98:     private final Map<String, Object> producerConfigs;
99:     private final Map<String, Object> consumerConfigs;
100:     private final Callback<ConsumerRecord<K, V>> consumedCallback;
