441:     private void poll() {
442:         try {
443:             ConsumerRecords<K, V> records = consumer.poll(Duration.ofMillis(Integer.MAX_VALUE));
444:             for (ConsumerRecord<K, V> record : records)
445:                 consumedCallback.onCompletion(null, record);
446:         } catch (WakeupException e) {
447:             // Expected on get() or stop(). The calling code should handle this
448:             throw e;
449:         } catch (KafkaException e) {
450:             log.error("Error polling: ", e);
451:             if (reportErrorsToCallback) {
452:                 consumedCallback.onCompletion(e, null);
453:             }
454:         }
455:     }
456: 
457:     /**
458:      * This method finds the end offsets of the Kafka log's topic partitions, optionally retrying
459:      * if the {@code listOffsets()} method of the admin client throws a {@link RetriableException}.
460:      *
461:      * @param shouldRetry Boolean flag to enable retry for the admin client {@code listOffsets()} call.
462:      * @see TopicAdmin#retryEndOffsets
463:      */
464:     private void readToLogEnd(boolean shouldRetry) {
465:         Set<TopicPartition> assignment = consumer.assignment();
466:         Map<TopicPartition, Long> endOffsets = readEndOffsets(assignment, shouldRetry);
467:         log.trace("Reading to end of log offsets {}", endOffsets);
468: 
469:         while (!endOffsets.isEmpty()) {
470:             Iterator<Map.Entry<TopicPartition, Long>> it = endOffsets.entrySet().iterator();
471:             while (it.hasNext()) {
472:                 Map.Entry<TopicPartition, Long> entry = it.next();
473:                 TopicPartition topicPartition = entry.getKey();
474:                 long endOffset = entry.getValue();
475:                 long lastConsumedOffset = consumer.position(topicPartition);
476:                 if (lastConsumedOffset >= endOffset) {
477:                     log.trace("Read to end offset {} for {}", endOffset, topicPartition);
478:                     it.remove();
479:                 } else {
480:                     log.trace("Behind end offset {} for {}; last-read offset is {}",
481:                             endOffset, topicPartition, lastConsumedOffset);
482:                     poll();
483:                     break;
484:                 }
485:             }
486:         }
487:     }
488: 
489:     // Visible for testing
490:     /**
491:      * Read to the end of the given list of topic partitions
492:      * @param assignment the topic partitions to read to the end of
493:      * @param shouldRetry boolean flag to enable retry for the admin client {@code listOffsets()} call.
494:      * @throws UnsupportedVersionException if the log's consumer is using the "read_committed" isolation level (and
495:      * therefore a separate admin client is required to read end offsets for the topic), but the broker does not support
496:      * reading end offsets using an admin client
497:      */
498:     Map<TopicPartition, Long> readEndOffsets(Set<TopicPartition> assignment, boolean shouldRetry) throws UnsupportedVersionException {
499:         log.trace("Reading to end of offset log");
500: 
501:         // Note that we'd prefer to not use the consumer to find the end offsets for the assigned topic partitions.
502:         // That is because it's possible that the consumer is already blocked waiting for new records to appear, when
503:         // the consumer is already at the end. In such cases, using 'consumer.endOffsets(...)' will block until at least
504:         // one more record becomes available, meaning we can't even check whether we're at the end offset.
505:         // Since all we're trying to do here is get the end offset, we should use the supplied admin client
506:         // (if available) to obtain the end offsets for the given topic partitions.
507: 
508:         // Deprecated constructors do not provide an admin supplier, so the admin is potentially null.
509:         if (admin != null) {
510:             // Use the admin client to immediately find the end offsets for the assigned topic partitions.
511:             // Unlike using the consumer
512:             try {
513:                 if (shouldRetry) {
514:                     return admin.retryEndOffsets(assignment,
515:                             ADMIN_CLIENT_RETRY_DURATION,
516:                             ADMIN_CLIENT_RETRY_BACKOFF_MS);
517:                 }
518: 
519:                 return admin.endOffsets(assignment);
520:             } catch (UnsupportedVersionException e) {
521:                 // This may happen with really old brokers that don't support the auto topic creation
522:                 // field in metadata requests
523:                 if (requireAdminForOffsets) {
524:                     // Should be handled by the caller during log startup
525:                     throw e;
526:                 }
527:                 log.debug("Reading to end of log offsets with consumer since admin client is unsupported: {}", e.getMessage());
